+					Parameters: map[string]any{"type": "object", "properties": map[string]any{}},
+				},
+				ReadOnly: readOnly,
+			},
+			Exec: func(ctx context.Context, env ExecutionEnvironment, args map[string]any) (any, error) {
+				start := time.Now()
