+		}
+		t := Task{
+			ID:              s.nextID,
+			Type:            taskType,
+			Description:     tt.Title,
+			Prompt:          tt.Prompt,
+			Status:          TaskOpen,
+			ReasoningEffort: tt.ReasoningEffort,
+			Insert:          tt.Insert,
+		}
+		s.nextID++
+		s.tasks = append(s.tasks, t)
+	}
+
+	// Auto-start the first task.
+	if len(s.tasks) > 0 {
+		s.tasks[0].Status = TaskInProgress
+	}
+
