+			updProps := items["properties"].(map[string]any)
+			effort := updProps["reasoning_effort"].(map[string]any)
+			gotEnum, ok := effort["enum"].([]string)
+			if !ok {
+				t.Fatalf("enum missing from reasoning_effort schema: %v", effort)
+			}
