+			t.Errorf("unexpected method: %s", r.Method)
+		}
+		w.Header().Set("Content-Type", "application/json")
+		fmt.Fprint(w, tasksJSON)
+	}))
+	defer ts.Close()
+
+	addr := ts.URL[len("http://"):]
+	cmd := fetchTasks(addr)
+	msg := cmd()
+
+	result, ok := msg.(tasksResult)
+	if !ok {
