+func TestFocusTool_UpDown(t *testing.T) {
+	m := model{
+		messages: []chatMessage{
+			{Kind: msgTool, Tool: &toolCallInfo{Name: "a", Done: true}},
+			{Kind: msgTool, Tool: &toolCallInfo{Name: "b", Done: true}},
