+		agent.TaskOpen:       "○",
+		agent.TaskInProgress: "◐",
+		agent.TaskDone:       "●",
+		agent.TaskCancelled:  "✗",
+	}
+
+	for _, t := range tasks {
+		icon := statusIcon[t.Status]
+		if icon == "" {
+			icon = "?"
+		}
+		b.WriteString(fmt.Sprintf("  %s [%d] %s — %s", icon, t.ID, t.Type, t.Description))
+		if len(t.DependsOn) > 0 {
