+		}
+		// Split at the first `">` before the parameter block. If there's no
+		// `">` (value not terminated with a quote-close-bracket), fall back to
+		// splitting at the `<` of the parameter tag.
+		idx := strings.Index(s[:openMatch[0]], `">`)
