+			paramValue := tail[valStart:valEnd]
+			// Strip trailing </parameter> (case-insensitive) if present.
+			lowerVal := strings.ToLower(paramValue)
+			if cut := strings.LastIndex(lowerVal, "</parameter>"); cut >= 0 {
+				paramValue = paramValue[:cut]
+			}
